static ge::graphStatus InferShape(gert::InferShapeContext *context)
{
    // x: [M, K], w (we will pass transposed in Python): [K, N]
    const gert::Shape *x_shape = context->GetInputShape(0);
    const gert::Shape *w_shape = context->GetInputShape(1);
    if (!x_shape || !w_shape) {
        return GRAPH_FAILED;
    }
    const auto &x_orig = x_shape->GetOriginShape();
    const auto &w_orig = w_shape->GetOriginShape();
    if (x_orig.GetDimNum() < 2 || w_orig.GetDimNum() < 2) {
        return GRAPH_FAILED;
    }
    std::vector<int64_t> y_dims = {x_orig.GetDim(x_orig.GetDimNum() - 2), w_orig.GetDim(w_orig.GetDimNum() - 1)};
    gert::Shape *y_shape = context->GetOutputShape(0);
    y_shape->SetOriginShape(y_dims);
    y_shape->SetStorageShape(y_dims);
    return GRAPH_SUCCESS;
}

